import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"about/roadmap.md","filePath":"about/roadmap.md"}'),o={name:"about/roadmap.md"};function n(s,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>What we&#39;re building next, why it matters, and how to influence it.</p><p>Priority reflects current thinking — not a commitment. Dates are targets, not promises. File an issue or <a href="mailto:insposearch.engine@gmail.com" target="_blank" rel="noreferrer">email us</a> if something here is wrong for your use case.</p><h2 id="now-shipping-in-the-next-4–6-weeks" tabindex="-1">Now (shipping in the next 4–6 weeks) <a class="header-anchor" href="#now-shipping-in-the-next-4–6-weeks" aria-label="Permalink to &quot;Now (shipping in the next 4–6 weeks)&quot;">​</a></h2><h3 id="source-health-dashboard" tabindex="-1">Source health dashboard <a class="header-anchor" href="#source-health-dashboard" aria-label="Permalink to &quot;Source health dashboard&quot;">​</a></h3><p>Live status page showing which adapters are responding, average latency, and recent error rate. Lets contributors know when a source needs attention before users file a ticket. <strong>Why it matters:</strong> with 2,400+ sources, silent breakage is the main failure mode.</p><h3 id="metadata-quality-pass" tabindex="-1">Metadata quality pass <a class="header-anchor" href="#metadata-quality-pass" aria-label="Permalink to &quot;Metadata quality pass&quot;">​</a></h3><p>Fill the most common empty fields (artist, date, medium) across the top 50 sources by traffic. Currently some adapters drop useful fields because of shallow response mapping. <strong>Why it matters:</strong> metadata is what turns a thumbnail into research.</p><h3 id="institutional-outreach" tabindex="-1">Institutional outreach <a class="header-anchor" href="#institutional-outreach" aria-label="Permalink to &quot;Institutional outreach&quot;">​</a></h3><p>Direct partnership conversations with museums and archives interested in being indexed. See <a href="https://insposearch.pages.dev/institutions.html" target="_blank" rel="noreferrer">institutions page</a>. <strong>Why it matters:</strong> the quickest path to better metadata is asking the source.</p><hr><h2 id="next-q2-q3-2026" tabindex="-1">Next (Q2 / Q3 2026) <a class="header-anchor" href="#next-q2-q3-2026" aria-label="Permalink to &quot;Next (Q2 / Q3 2026)&quot;">​</a></h2><h3 id="saved-collections" tabindex="-1">Saved collections <a class="header-anchor" href="#saved-collections" aria-label="Permalink to &quot;Saved collections&quot;">​</a></h3><p>Bookmark images into named collections (localStorage first, then optional sync via Cloudflare KV). Export to CSV with attribution.</p><h3 id="download-queue-with-attribution" tabindex="-1">Download queue with attribution <a class="header-anchor" href="#download-queue-with-attribution" aria-label="Permalink to &quot;Download queue with attribution&quot;">​</a></h3><p>Batch download selected images alongside a credits file — title, creator, date, source URL, licence. For research use where citations are required.</p><h3 id="advanced-filters-in-the-search-bar" tabindex="-1">Advanced filters in the search bar <a class="header-anchor" href="#advanced-filters-in-the-search-bar" aria-label="Permalink to &quot;Advanced filters in the search bar&quot;">​</a></h3><p>Date range, medium, source category — toggleable without leaving the grid.</p><h3 id="similar-image-search" tabindex="-1">Similar image search <a class="header-anchor" href="#similar-image-search" aria-label="Permalink to &quot;Similar image search&quot;">​</a></h3><p>Reverse lookup via perceptual hash. Select an image → find visually related works across the full corpus.</p><h3 id="pwa-offline-mode" tabindex="-1">PWA / offline mode <a class="header-anchor" href="#pwa-offline-mode" aria-label="Permalink to &quot;PWA / offline mode&quot;">​</a></h3><p>Installable, with offline browsing of previously cached searches.</p><hr><h2 id="later-exploring-—-may-or-may-not-happen" tabindex="-1">Later (exploring — may or may not happen) <a class="header-anchor" href="#later-exploring-—-may-or-may-not-happen" aria-label="Permalink to &quot;Later (exploring — may or may not happen)&quot;">​</a></h2><h3 id="public-read-only-api" tabindex="-1">Public read-only API <a class="header-anchor" href="#public-read-only-api" aria-label="Permalink to &quot;Public read-only API&quot;">​</a></h3><p>Programmatic access to <code>/search</code> and <code>/sources</code> with a rate-limited public key. Already exists internally via <a href="/docs/reference/api-contracts"><code>api/worker.js</code></a> — the work is documenting, rate-limiting, and supporting it.</p><h3 id="browser-extension" tabindex="-1">Browser extension <a class="header-anchor" href="#browser-extension" aria-label="Permalink to &quot;Browser extension&quot;">​</a></h3><p>Right-click any web image → &quot;Search InspoSearch.&quot;</p><h3 id="embed-widget" tabindex="-1">Embed widget <a class="header-anchor" href="#embed-widget" aria-label="Permalink to &quot;Embed widget&quot;">​</a></h3><p>Museums and archives can embed a narrow-scope InspoSearch on their own domain.</p><h3 id="collaborative-boards-via-crdts" tabindex="-1">Collaborative boards via CRDTs <a class="header-anchor" href="#collaborative-boards-via-crdts" aria-label="Permalink to &quot;Collaborative boards via CRDTs&quot;">​</a></h3><p>Shared boards without a server — already partially wired through the <code>BOARDS</code> KV namespace; the research question is how to do multi-user edits without a coordinator.</p><h3 id="inspoenrich-commercial-separate-product" tabindex="-1">InspoEnrich (commercial, separate product) <a class="header-anchor" href="#inspoenrich-commercial-separate-product" aria-label="Permalink to &quot;InspoEnrich (commercial, separate product)&quot;">​</a></h3><p>A metadata enrichment service for institutions, built on the same engine. Keeps the InspoSearch app free and AGPL; funds sustainability. Early-stage — more in 2027.</p><hr><h2 id="recently-shipped" tabindex="-1">Recently shipped <a class="header-anchor" href="#recently-shipped" aria-label="Permalink to &quot;Recently shipped&quot;">​</a></h2><p>See the <a href="/docs/about/changelog">changelog</a> for dated details. Highlights from 1.1.0:</p><ul><li>Workers AI as default vision provider (LLaVA 1.5) — analyse works without keys</li><li>3-lane load-more dispatcher — infinite scroll survives past page 5</li><li>RRF fusion + MMR diversification — fewer near-duplicates, more visual variety</li><li>Deep-link URL state for shareable queries</li><li>Opt-in community metadata contribution</li></ul><hr><h2 id="influencing-the-roadmap" tabindex="-1">Influencing the roadmap <a class="header-anchor" href="#influencing-the-roadmap" aria-label="Permalink to &quot;Influencing the roadmap&quot;">​</a></h2><ul><li><strong>Request a feature:</strong> <a href="https://github.com/GI-Synth/InspoSearch/issues/new" target="_blank" rel="noreferrer">open an issue</a> with the <code>feature-request</code> label. Tell us the use case, not just the feature name — we prioritise by how many real workflows something unblocks</li><li><strong>Vote:</strong> thumbs-up reactions on existing issues count</li><li><strong>Fund specific work:</strong> <a href="mailto:insposearch.engine@gmail.com" target="_blank" rel="noreferrer">email us</a> — directed contributions can reshuffle priority</li><li><strong>Ship it yourself:</strong> see <a href="/docs/about/contributing">Contributing</a></li></ul>',41)])])}const m=a(o,[["render",n]]);export{p as __pageData,m as default};
